SELECT product_id, msds_id, msds_revision
FROM msds
ORDER BY date_of_msds DESC;

SELECT trade_name, cas_number, type_utilisation
FROM chemical_products
WHERE status = 'pending';

SELECT cp.product_id, TAN(m.msds_revision) AS tan_value
FROM chemical_products AS cp
INNER JOIN msds AS m ON cp.product_id = m.product_id;

SELECT * FROM chemical_products 
WHERE product_id IN (
    SELECT product_id FROM restrictions WHERE restriction_type = 'handling'
    INTERSECT
    SELECT product_id FROM (
        SELECT product_id FROM approvals WHERE approved_by = (SELECT user_id FROM users WHERE user_name = 'John Doe')
        UNION
        SELECT product_id FROM comments WHERE commentedBy = (SELECT user_id FROM users WHERE user_name = 'John Doe')
    )
);
